from zeep import Client
from zeep.exceptions import Fault
import re

def validate_input(policy_number, customer_name):
    if not re.match(r'^[A-Z0-9-]+$', policy_number):
        raise ValueError("Invalid policy number format.")
    if not re.match(r'^[A-Za-z\s]+$', customer_name):
        raise ValueError("Invalid customer name format.")

def get_insurance_quote(policy_number, customer_name):
    validate_input(policy_number, customer_name)
    
    client = Client('https://example.com/insurance_service?wsdl')
    
    try:
        response = client.service.GetInsuranceQuote(PolicyNumber=policy_number, CustomerName=customer_name)
        return response
    except Fault as e:
        print(f"Error: {e}")

